package com.google.gson.metrics;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.io.Reader;
import java.io.StringWriter;
import java.lang.reflect.Method;
import java.net.URL;
import java.util.zip.ZipEntry;
import java.util.zip.ZipFile;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

public class ParseBenchmarkTest {

  private static final String ZIP_RESOURCE_PATH = "/ParseBenchmarkData.zip";
  private static final String TEST_FILE_NAME = "test.json";
  private static final String TEST_CONTENT = "{\"key\":\"value\"}";

  private Method resourceToStringMethod;

  @BeforeEach
  public void setUp() throws Exception {
    resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToStringMethod.setAccessible(true);
  }

  @Test
  public void testResourceToString_readsContentFromZipEntry() throws Exception {
    // Mock ZipFile constructor to avoid actual file access
    try (MockedConstruction<ZipFile> mockedZipFile = Mockito.mockConstruction(ZipFile.class,
        (mock, context) -> {
          ZipEntry zipEntry = new ZipEntry(TEST_FILE_NAME);
          when(mock.getEntry(TEST_FILE_NAME)).thenReturn(zipEntry);

          InputStream inputStream = new ByteArrayInputStream(TEST_CONTENT.getBytes());
          when(mock.getInputStream(zipEntry)).thenReturn(inputStream);

          doNothing().when(mock).close();
        })) {

      // Mock getResourceFile to return a dummy File to avoid FileNotFoundException and URI issues
      Method getResourceFileMethod = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
      getResourceFileMethod.setAccessible(true);

      // Replace getResourceFile call via reflection by temporarily overriding it with a proxy instance
      // Since we cannot mock private static method easily, we replace the File returned by getResourceFile by reflection

      // Use reflection to set a dummy file for the zip file path
      // The resourceToString method calls new ZipFile(getResourceFile(...)),
      // so we replace getResourceFile to return a dummy File that triggers ZipFile constructor mock

      // Create a dummy File instance (can be any file, won't be used because ZipFile constructor is mocked)
      File dummyFile = new File("dummy.zip");

      // Use reflection to temporarily replace getResourceFile method by a proxy invocation handler is not trivial,
      // so instead, we use a spy on ParseBenchmark class to override getResourceFile,
      // but since it's static private, we can't do that easily.
      // So instead, we use a trick: create a subclass with overridden method and invoke resourceToString on it.
      // But resourceToString is static private, so no override possible.
      // So we use reflection to replace the getResourceFile method temporarily via Unsafe or MethodHandles is complicated.
      // Instead, we use a workaround: temporarily rename the ZIP_RESOURCE_PATH to a file path that will cause ZipFile constructor to be called,
      // but since ZipFile constructor is mocked, it won't try to open actual file.

      // So we invoke resourceToString with TEST_FILE_NAME and rely on mocked ZipFile constructor to intercept.

      String result = (String) resourceToStringMethod.invoke(null, TEST_FILE_NAME);

      assertEquals(TEST_CONTENT, result);
    }
  }

  @Test
  public void testResourceToString_closesZipFileOnException() throws Exception {
    // Mock ZipFile constructor to throw IOException on getEntry and verify close is called
    try (MockedConstruction<ZipFile> mockedZipFile = Mockito.mockConstruction(ZipFile.class,
        (mock, context) -> {
          when(mock.getEntry(TEST_FILE_NAME)).thenThrow(new IOException("forced exception"));
          doNothing().when(mock).close();
        })) {

      Exception thrown = assertThrows(Exception.class, () -> {
        resourceToStringMethod.invoke(null, TEST_FILE_NAME);
      });

      // Verify that close was called on the mocked ZipFile
      ZipFile mockZipFile = mockedZipFile.constructed().get(0);
      verify(mockZipFile).close();

      // Verify that the exception message contains "forced exception"
      assertTrue(thrown.getCause() instanceof IOException);
      assertEquals("forced exception", thrown.getCause().getMessage());
    }
  }

}
